CREATE OR REPLACE FORCE EDITIONABLE VIEW "V_SP_USUARIOS" ("COMPANIA", "CICLO", "CODIGORUTA", "ANO", "PERIODO", "NOMBRE_PERIODO", "NOMBRE", "CODIGOINTERNO", "CODIGOANTERIOR", "DIRTECNICA", "DIRGUIA", "USO", "ESTRATO", "ACUEDUCTO", "ASEO", "ASEOBARRIDO", "ALCANTARILLADO", "ALUMBRADO", "PORCENTAJEAPLICAR", "ESTRATOASEO", "PESOASEO", "FRECUENCIAASEOSEMANA", "ESTADO", "AREA", "COMENTARIOS", "NOTACREDITO", "MEDIDOR", "NUMERODIGITOS", "AFORADOR", "LECTURA1", "LECTURA2", "LECTURA3", "LECTURA4", "LECTURA5", "LECTURA6", "LECTURA", "LECTURAAFORO", "PERIODOSATRASO", "BANCOPERANTERIOR", "FECHAPAGOPERANTERIOR", "PAQUETEPAGOPERANTERIOR", "NOFECHAPAGOPERANTERIOR", "BANCOPERPROCESO", "FECHAPAGOPERPROCESO", "PAQUETEPAGOPERPROCESO", "NOFECHAPAGOPERPROCESO", "TOTFACTURAPERACTUAL", "CONSUMO1", "CONSUMO2", "CONSUMO3", "CONSUMO4", "CONSUMO5", "CONSUMO6", "CONSUMO", "CONSUMOPROM", "CONSUMOAFORO", "PERIODOSNOCOBROFIN", "PERIODOSNOCOBROFAC", "PERIODOSINLECTURA", "ACUMULADO", "FIMM", "TIPOLECTURA", "ESTRATOALUMBRADO", "INQUILINATOS", "FACTURA", "INDDESHABITADO", "TOTALIZADOR", "ESTADOMEDIDOR", "CHAPETAS", "FRECUENCIARECOLECCION", "TIPOCOBRO", "TASACAR", "NOUNDMULTIUSUARIO", "ACSINMEDICION", "ALSINMEDICION", "INDRECAUDADO", "NOTADEBITO", "SEPARACIONENFUENTE", "NOPUERTAPUERTA", "APARTAMENTO", "CODIGO_EXTERNO", "AUTORIZAMODIFICACION", "AUTORIZARBORRADO", "PLANTA", "TOTFACTURAPERANTERIOR", "TOTALDEUDA", "SUBSINMEDICION", "SOBRESINMEDICION", "SUBALCSINMEDICION", "SOBREALCSINMEDICION", "DEUDA", "CARGOFIJO", "CARGOFIJOAL", "CONSUMOBASICO", "VALORBASICO", "VALORCOMPLEMENTARIO", "VALORSUNTUARIO", "VALORALCBASICO", "TOTALALUMBRADO", "TOTALACUEDUCTO", "TOTALALCANTARILLADO", "TOTALASEO", "VASEOUNICO", "VASEODOMICILIARIO", "VASEOBARRIDO", "VASEOCONSUMO", "SUBSIDIO", "SOBREPRECIO", "SUBACUEDUCTO", "SUBALCANTARILLADO", "SUBASEO", "SUBFIJO", "SUBFIJOALC", "SUBCONSUMOAC", "SUBCONSUMOAL", "SOBREACUEDUCTO", "SOBREALCANTARILLADO", "SOBREASEO", "SOBREFIJO", "SOBREFIJOALC", "SOBRECONSUMOAC", "SOBRECONSUMOAL", "VALORALCCOMPLEMENTARIO", "VALORALCSUNTUARIO", "CONSUMOCOMPLEMENTARIO", "CONSUMOSUNTUARIO", "ALCBASICO", "ALCCOMPLEMENTARIO", "ALCSUNTUARIO", "DESVIOSIGNIFICATIVO", "EMPRESAASEOEXT", "PINTADEUDATERCE", "VDESHABITADO", "VTRAMOEXCEDENTE", "SUBBARR_LIM", "SOBBARR_LIM", "SUBDISP_FINAL", "SOBDISP_FINAL", "SUBMANEJO_REC", "SOBMANEJO_REC", "SUBRECOLECCION", "SOBRECOLECCION", "SUBTRAMO", "SOBTRAMO", "SUBDESHABITADO", "SOBDESHABITADO", "CODTOTALIZADOR", "FREC_RECO", "FREC_BARRI", "TIPODEAFORO", "HOGAR_COMUNITARIO", "CARACTERIZACION_ALC", "BARRIO", "CONSUMOBASICOALC", "CONSUMOCOMPLEMENTARIOALC", "CONSUMOSUNTUARIOALC", "CONSUMOALC", "CONSUMOACU", "CONSUMOMANUAL", "CODMACROMEDIDOR", "PORMICRO", "SINDESCUENTO", "MATRICULA", "VALASEOCCS_720", "SUBCCS_720", "SOBCCS_720", "VALASEOCBLS_720", "SUBCBLS_720", "SOBCBLS_720", "VALASEOCLUS_720", "SUBCLUS_720", "SOBCLUS_720", "VALASEOCRT_720", "SUBCRT_720", "SOBCRT_720", "VALASEOCDF_720", "SUBCDF_720", "SOBCDF_720", "VALASEOCTL_720", "SUBCTL_720", "SOBCTL_720", "VALASEOVBA_720", "SUBVBA_720", "SOBVBA_720", "SERVNORECLAMADO", "VALORASEO", "FECHA_PAGO", "BANCO_PAGO", "PAQUETE_PAGO", "NOM_BANCO_PAGO_TER", "NOM_BANCOPERPROCESO", "TOTAL_CONV", "FECHA_PAGO_CONV", "BANCO_PAGO_CONV", "PAQUETE_PAGO_CONV", "NOM_BANCO_PAGO_CONV", "NOM_BANCOPERANTERIOR", "VALORASEO_ANT", "FECHA_PAGO_ANT", "BANCO_PAGO_ANT", "PAQUETE_PAGO_ANT", "NOM_BANCO_PAGO_TER_ANT", "TOTAL_CONV_ANT", "FECHA_PAGO_CONV_ANT", "BANCO_PAGO_CONV_ANT", "PAQUETE_PAGO_CONV_ANT", "NOM_BANCO_PAGO_CONV_ANT", "DATE_MODIFIED", "CREATED_BY", "DATE_CREATED", "MODIFIED_BY") AS 
  WITH FRECUENCIA AS
  (SELECT CODIGO COMPANIA,
    PCK_SYSMAN_UTL.FC_PAR(CODIGO, 'FRECUENCIA PERIODOS DE FACTURACION', 74, SYSDATE, NULL) FREC
  FROM COMPANIA
  )
SELECT
  /*+ INDEX(SP_USUARIO PK_SP_USUARIO) */
  SP_USUARIO.COMPANIA,
  SP_USUARIO.CICLO,
  SP_USUARIO.CODIGORUTA,
  SP_USUARIO.ANO,
  SP_USUARIO.PERIODO,
  PCK_SERVICIOS_PUBLICOS.FC_NOMBREPERIODO(SP_USUARIO.COMPANIA,SP_USUARIO.ANO,SP_USUARIO.PERIODO,FRECUENCIA.FREC) NOMBRE_PERIODO,
  SP_USUARIO.PRIMERAPELLIDO
  || ' '
  || SP_USUARIO.SEGUNDOAPELLIDO
  || ' '
  || SP_USUARIO.NOMBRES NOMBRE,
  SP_USUARIO.CODIGOINTERNO,
  SP_USUARIO.CODIGOANTERIOR,
  SP_USUARIO.DIRTECNICA,
  SP_USUARIO.DIRGUIA,
  SP_USUARIO.USO,
  SP_USUARIO.ESTRATO,
  SP_USUARIO.ACUEDUCTO,
  SP_USUARIO.ASEO,
  SP_USUARIO.ASEOBARRIDO,
  SP_USUARIO.ALCANTARILLADO,
  SP_USUARIO.ALUMBRADO,
  SP_USUARIO.PORCENTAJEAPLICAR,
  SP_USUARIO.ESTRATOASEO,
  SP_USUARIO.PESOASEO,
  SP_USUARIO.FRECUENCIAASEOSEMANA,
  SP_USUARIO.ESTADO,
  SP_USUARIO.AREA,
  SP_USUARIO.COMENTARIOS,
  SP_USUARIO.NOTACREDITO,
  SP_USUARIO.MEDIDOR,
  SP_USUARIO.NUMERODIGITOS,
  SP_USUARIO.AFORADOR,
  SP_USUARIO.LECTURA1,
  SP_USUARIO.LECTURA2,
  SP_USUARIO.LECTURA3,
  SP_USUARIO.LECTURA4,
  SP_USUARIO.LECTURA5,
  SP_USUARIO.LECTURA6,
  SP_USUARIO.LECTURA,
  SP_USUARIO.LECTURAAFORO,
  SP_USUARIO.PERIODOSATRASO,
  SP_USUARIO.BANCOPERANTERIOR,
  SP_USUARIO.FECHAPAGOPERANTERIOR,
  SP_USUARIO.PAQUETEPAGOPERANTERIOR,
  SP_USUARIO.NOFECHAPAGOPERANTERIOR,
  SP_USUARIO.BANCOPERPROCESO,
  SP_USUARIO.FECHAPAGOPERPROCESO,
  SP_USUARIO.PAQUETEPAGOPERPROCESO,
  SP_USUARIO.NOFECHAPAGOPERPROCESO,
  SP_USUARIO.TOTFACTURAPERACTUAL,
  SP_USUARIO.CONSUMO1,
  SP_USUARIO.CONSUMO2,
  SP_USUARIO.CONSUMO3,
  SP_USUARIO.CONSUMO4,
  SP_USUARIO.CONSUMO5,
  SP_USUARIO.CONSUMO6,
  SP_USUARIO.CONSUMO,
  SP_USUARIO.CONSUMOPROM,
  SP_USUARIO.CONSUMOAFORO,
  SP_USUARIO.PERIODOSNOCOBROFIN,
  SP_USUARIO.PERIODOSNOCOBROFAC,
  SP_USUARIO.PERIODOSINLECTURA,
  SP_USUARIO.ACUMULADO,
  SP_USUARIO.FIMM,
  SP_USUARIO.TIPOLECTURA,
  SP_USUARIO.ESTRATOALUMBRADO,
  SP_USUARIO.INQUILINATOS,
  SP_USUARIO.FACTURA,
  SP_USUARIO.INDDESHABITADO,
  SP_USUARIO.TOTALIZADOR,
  SP_USUARIO.ESTADOMEDIDOR,
  SP_USUARIO.CHAPETAS,
  SP_USUARIO.FRECUENCIARECOLECCION,
  SP_USUARIO.TIPOCOBRO,
  SP_USUARIO.TASACAR,
  SP_USUARIO.NOUNDMULTIUSUARIO,
  SP_USUARIO.ACSINMEDICION,
  SP_USUARIO.ALSINMEDICION,
  SP_USUARIO.INDRECAUDADO,
  SP_USUARIO.NOTADEBITO,
  SP_USUARIO.SEPARACIONENFUENTE,
  SP_USUARIO.NOPUERTAPUERTA,
  SP_USUARIO.APARTAMENTO,
  SP_USUARIO.CODIGO_EXTERNO,
  SP_USUARIO.AUTORIZAMODIFICACION,
  SP_USUARIO.AUTORIZARBORRADO,
  SP_USUARIO.PLANTA,
  SP_USUARIO.TOTFACTURAPERANTERIOR,
  SP_USUARIO.TOTALDEUDA,
  SP_USUARIO.SUBSINMEDICION,
  SP_USUARIO.SOBRESINMEDICION,
  SP_USUARIO.SUBALCSINMEDICION,
  SP_USUARIO.SOBREALCSINMEDICION,
  SP_USUARIO.DEUDA,
  SP_USUARIO.CARGOFIJO,
  SP_USUARIO.CARGOFIJOAL,
  SP_USUARIO.CONSUMOBASICO,
  SP_USUARIO.VALORBASICO,
  SP_USUARIO.VALORCOMPLEMENTARIO,
  SP_USUARIO.VALORSUNTUARIO,
  SP_USUARIO.VALORALCBASICO,
  SP_USUARIO.TOTALALUMBRADO,
  SP_USUARIO.TOTALACUEDUCTO,
  SP_USUARIO.TOTALALCANTARILLADO,
  SP_USUARIO.TOTALASEO,
  SP_USUARIO.VASEOUNICO,
  SP_USUARIO.VASEODOMICILIARIO,
  SP_USUARIO.VASEOBARRIDO,
  SP_USUARIO.VASEOCONSUMO,
  SP_USUARIO.SUBSIDIO,
  SP_USUARIO.SOBREPRECIO,
  SP_USUARIO.SUBACUEDUCTO,
  SP_USUARIO.SUBALCANTARILLADO,
  SP_USUARIO.SUBASEO,
  SP_USUARIO.SUBFIJO,
  SP_USUARIO.SUBFIJOALC,
  SP_USUARIO.SUBCONSUMOAC,
  SP_USUARIO.SUBCONSUMOAL,
  SP_USUARIO.SOBREACUEDUCTO,
  SP_USUARIO.SOBREALCANTARILLADO,
  SP_USUARIO.SOBREASEO,
  SP_USUARIO.SOBREFIJO,
  SP_USUARIO.SOBREFIJOALC,
  SP_USUARIO.SOBRECONSUMOAC,
  SP_USUARIO.SOBRECONSUMOAL,
  SP_USUARIO.VALORALCCOMPLEMENTARIO,
  SP_USUARIO.VALORALCSUNTUARIO,
  SP_USUARIO.CONSUMOCOMPLEMENTARIO,
  SP_USUARIO.CONSUMOSUNTUARIO,
  SP_USUARIO.ALCBASICO,
  SP_USUARIO.ALCCOMPLEMENTARIO,
  SP_USUARIO.ALCSUNTUARIO,
