  SP_USUARIO.VDESHABITADO,
  SP_USUARIO.VTRAMOEXCEDENTE,
  SP_USUARIO.SUBBARR_LIM,
  SP_USUARIO.SOBBARR_LIM,
  SP_USUARIO.SUBDISP_FINAL,
  SP_USUARIO.SOBDISP_FINAL,
  SP_USUARIO.SUBMANEJO_REC,
  SP_USUARIO.SOBMANEJO_REC,
  SP_USUARIO.SUBRECOLECCION,
  SP_USUARIO.SOBRECOLECCION,
  SP_USUARIO.SUBTRAMO,
  SP_USUARIO.SOBTRAMO,
  SP_USUARIO.SUBDESHABITADO,
  SP_USUARIO.SOBDESHABITADO,
  SP_USUARIO.CODTOTALIZADOR,
  SP_USUARIO.FREC_RECO,
  SP_USUARIO.FREC_BARRI,
  SP_USUARIO.TIPODEAFORO,
  SP_USUARIO.HOGAR_COMUNITARIO,
  SP_USUARIO.CARACTERIZACION_ALC,
  SP_USUARIO.BARRIO,
  SP_USUARIO.CONSUMOBASICOALC,
  SP_USUARIO.CONSUMOCOMPLEMENTARIOALC,
  SP_USUARIO.CONSUMOSUNTUARIOALC,
  SP_USUARIO.CONSUMOALC,
  SP_USUARIO.CONSUMOACU,
  SP_USUARIO.CONSUMOMANUAL,
  SP_USUARIO.CODMACROMEDIDOR,
  SP_USUARIO.PORMICRO,
  SP_USUARIO.SINDESCUENTO,
  SP_USUARIO.MATRICULA,
  SP_USUARIO.VALASEOCCS_720,
  SP_USUARIO.SUBCCS_720,
  SP_USUARIO.SOBCCS_720,
  SP_USUARIO.VALASEOCBLS_720,
  SP_USUARIO.SUBCBLS_720,
  SP_USUARIO.SOBCBLS_720,
  SP_USUARIO.VALASEOCLUS_720,
  SP_USUARIO.SUBCLUS_720,
  SP_USUARIO.SOBCLUS_720,
  SP_USUARIO.VALASEOCRT_720,
  SP_USUARIO.SUBCRT_720,
  SP_USUARIO.SOBCRT_720,
  SP_USUARIO.VALASEOCDF_720,
  SP_USUARIO.SUBCDF_720,
  SP_USUARIO.SOBCDF_720,
  SP_USUARIO.VALASEOCTL_720,
  SP_USUARIO.SUBCTL_720,
  SP_USUARIO.SOBCTL_720,
  SP_USUARIO.VALASEOVBA_720,
  SP_USUARIO.SUBVBA_720,
  SP_USUARIO.SOBVBA_720,
  SP_USUARIO.SERVNORECLAMADO,
  NVL(SP_HISTORIA_EXTERNA.VALORASEO,0) VALORASEO,
  SP_HISTORIA_EXTERNA.FECHA_PAGO,
  SP_HISTORIA_EXTERNA.BANCO_PAGO,
  SP_HISTORIA_EXTERNA.PAQUETE_PAGO,
  BANCO_TER.NOMBRE NOM_BANCO_PAGO_TER,
  BANCO_PER.NOMBRE NOM_BANCOPERPROCESO,
  (CASE SP_HISTORIA_CONVENIOS.NOCOBRAR WHEN 0 
   THEN NVL(SP_HISTORIA_CONVENIOS.TOTAL, 0)
   ELSE 0 END) TOTAL_CONV,
  SP_HISTORIA_CONVENIOS.FECHA_PAGO FECHA_PAGO_CONV,
  SP_HISTORIA_CONVENIOS.BANCO_PAGO BANCO_PAGO_CONV,
  SP_HISTORIA_CONVENIOS.PAQUETE_PAGO PAQUETE_PAGO_CONV,
  BANCO_CONV.NOMBRE NOM_BANCO_PAGO_CONV,
  BANCO_ANT.NOMBRE NOM_BANCOPERANTERIOR,
  NVL(HISTORIA_EXTERNA_ANT.VALORASEO,0) VALORASEO_ANT,
  HISTORIA_EXTERNA_ANT.FECHA_PAGO FECHA_PAGO_ANT,
  HISTORIA_EXTERNA_ANT.BANCO_PAGO BANCO_PAGO_ANT,
  HISTORIA_EXTERNA_ANT.PAQUETE_PAGO PAQUETE_PAGO_ANT,
  BANCO_TER_ANT.NOMBRE NOM_BANCO_PAGO_TER_ANT,
  NVL(HISTORIA_CONVENIOS_ANT.TOTAL,0) TOTAL_CONV_ANT,
  HISTORIA_CONVENIOS_ANT.FECHA_PAGO FECHA_PAGO_CONV_ANT,
  HISTORIA_CONVENIOS_ANT.BANCO_PAGO BANCO_PAGO_CONV_ANT,
  HISTORIA_CONVENIOS_ANT.PAQUETE_PAGO PAQUETE_PAGO_CONV_ANT,
  BANCO_CONV_ANT.NOMBRE NOM_BANCO_PAGO_CONV_ANT,
  SP_USUARIO.DATE_MODIFIED,
  SP_USUARIO.CREATED_BY,
  SP_USUARIO.DATE_CREATED,
  SP_USUARIO.MODIFIED_BY
FROM ((((((((SP_USUARIO
INNER JOIN FRECUENCIA
ON (SP_USUARIO.COMPANIA = FRECUENCIA.COMPANIA))
LEFT JOIN SP_HISTORIA_EXTERNA
ON (SP_USUARIO.PERIODO     = SP_HISTORIA_EXTERNA.PERIODO)
AND (SP_USUARIO.ANO        = SP_HISTORIA_EXTERNA.ANO)
AND (SP_USUARIO.CODIGORUTA = SP_HISTORIA_EXTERNA.CODIGORUTA)
AND (SP_USUARIO.CICLO      = SP_HISTORIA_EXTERNA.CICLO)
AND (SP_USUARIO.COMPANIA   = SP_HISTORIA_EXTERNA.COMPANIA))
LEFT JOIN SP_BANCOS BANCO_TER
ON (SP_HISTORIA_EXTERNA.COMPANIA    = BANCO_TER.COMPANIA)
AND (SP_HISTORIA_EXTERNA.BANCO_PAGO = BANCO_TER.CODIGO))
LEFT JOIN SP_BANCOS BANCO_PER
ON (SP_USUARIO.COMPANIA         = BANCO_PER.COMPANIA)
AND (SP_USUARIO.BANCOPERPROCESO = BANCO_PER.CODIGO))
LEFT JOIN SP_HISTORIA_CONVENIOS
ON (SP_USUARIO.COMPANIA    = SP_HISTORIA_CONVENIOS.COMPANIA)
AND (SP_USUARIO.CICLO      = SP_HISTORIA_CONVENIOS.CICLO)
AND (SP_USUARIO.CODIGORUTA = SP_HISTORIA_CONVENIOS.CODIGORUTA)
AND (SP_USUARIO.ANO        = SP_HISTORIA_CONVENIOS.ANO)
AND (SP_USUARIO.PERIODO    = SP_HISTORIA_CONVENIOS.PERIODO))
LEFT JOIN SP_BANCOS BANCO_CONV
ON (SP_HISTORIA_CONVENIOS.BANCO_PAGO = BANCO_CONV.CODIGO)
AND (SP_HISTORIA_CONVENIOS.COMPANIA  = BANCO_CONV.COMPANIA))
LEFT JOIN SP_BANCOS BANCO_ANT
ON (SP_USUARIO.BANCOPERANTERIOR = BANCO_ANT.CODIGO)
AND (SP_USUARIO.COMPANIA        = BANCO_ANT.COMPANIA))
LEFT JOIN (SP_HISTORIA_EXTERNA HISTORIA_EXTERNA_ANT
LEFT JOIN SP_BANCOS BANCO_TER_ANT
ON (HISTORIA_EXTERNA_ANT.BANCO_PAGO = BANCO_TER_ANT.CODIGO)
AND (HISTORIA_EXTERNA_ANT.COMPANIA  = BANCO_TER_ANT.COMPANIA))
ON (SP_USUARIO.COMPANIA             = HISTORIA_EXTERNA_ANT.COMPANIA)
AND (SP_USUARIO.CICLO               = HISTORIA_EXTERNA_ANT.CICLO)
AND (SP_USUARIO.CODIGORUTA          = HISTORIA_EXTERNA_ANT.CODIGORUTA)
AND (SP_USUARIO.ANO                 = PCK_SERVICIOS_PUBLICOS.FC_ANO_PERIODO_SIGUIENTE(HISTORIA_EXTERNA_ANT.COMPANIA, HISTORIA_EXTERNA_ANT.ANO, HISTORIA_EXTERNA_ANT.PERIODO, '0', FRECUENCIA.FREC))
AND (SP_USUARIO.PERIODO             = PCK_SERVICIOS_PUBLICOS.FC_ANO_PERIODO_SIGUIENTE(HISTORIA_EXTERNA_ANT.COMPANIA, HISTORIA_EXTERNA_ANT.ANO, HISTORIA_EXTERNA_ANT.PERIODO, '1', FRECUENCIA.FREC))
LEFT JOIN (SP_HISTORIA_CONVENIOS HISTORIA_CONVENIOS_ANT
LEFT JOIN SP_BANCOS BANCO_CONV_ANT
ON (HISTORIA_CONVENIOS_ANT.BANCO_PAGO = BANCO_CONV_ANT.CODIGO)
AND (HISTORIA_CONVENIOS_ANT.COMPANIA  = BANCO_CONV_ANT.COMPANIA))
ON (SP_USUARIO.COMPANIA               = HISTORIA_CONVENIOS_ANT.COMPANIA)
AND (SP_USUARIO.CICLO                 = HISTORIA_CONVENIOS_ANT.CICLO)
AND (SP_USUARIO.CODIGORUTA            = HISTORIA_CONVENIOS_ANT.CODIGORUTA)
AND (SP_USUARIO.ANO                   = PCK_SERVICIOS_PUBLICOS.FC_ANO_PERIODO_SIGUIENTE(HISTORIA_CONVENIOS_ANT.COMPANIA, HISTORIA_CONVENIOS_ANT.ANO, HISTORIA_CONVENIOS_ANT.PERIODO, '0', FRECUENCIA.FREC))
AND (SP_USUARIO.PERIODO               = PCK_SERVICIOS_PUBLICOS.FC_ANO_PERIODO_SIGUIENTE(HISTORIA_CONVENIOS_ANT.COMPANIA, HISTORIA_CONVENIOS_ANT.ANO, HISTORIA_CONVENIOS_ANT.PERIODO, '1', FRECUENCIA.FREC)));

   COMMENT ON COLUMN "V_SP_USUARIOS"."COMPANIA" IS 'Codigo de la compa?ia a la que pertenece el registro';
   COMMENT ON COLUMN "V_SP_USUARIOS"."ANO" IS 'A?o al que pertenece el registro';
   COMMENT ON COLUMN "V_SP_USUARIOS"."PERIODO" IS 'Identifica el periodo asociado en el registro';
   COMMENT ON COLUMN "V_SP_USUARIOS"."NOMBRE" IS 'nombre descriptivo asociado al codigo o identificador del registro';
   COMMENT ON COLUMN "V_SP_USUARIOS"."DATE_MODIFIED" IS 'Campo de auditoria que almacena la fecha de modificacion mas reciente.';
   COMMENT ON COLUMN "V_SP_USUARIOS"."CREATED_BY" IS 'Campo de auditoria que almacena el codigo del usuario que creo el registro.';
   COMMENT ON COLUMN "V_SP_USUARIOS"."DATE_CREATED" IS 'Campo de auditoria que almacena la fecha de creacion del registro.';
   COMMENT ON COLUMN "V_SP_USUARIOS"."MODIFIED_BY" IS 'Campo de auditoria que almacena el codigo del usuario que realizo modificacion mas reciente.';
